#include <stdio.h>
#include <string.h> // Required for strlen()
#include <ctype.h>  // Required for tolower()

int main() {
    char input_string[101]; // Allocate space for 100 characters + null terminator
    int vowel_count = 0;
    int i;

    // Read a line of text from stdin
    // fgets is safer than scanf("%s", ...) as it prevents buffer overflows
    // and can read strings with spaces.
    // It reads up to 100 characters or until a newline, storing the newline if present.
    if (fgets(input_string, sizeof(input_string), stdin) == NULL) {
        return 1; // Handle potential input error
    }

    // Remove the trailing newline character if fgets included it
    // This is important because a newline would be counted in strlen()
    // and could potentially be processed as a character.
    input_string[strcspn(input_string, "\n")] = '\0';

    // Iterate through the string character by character
    for (i = 0; input_string[i] != '\0'; i++) {
        // Convert the character to lowercase to simplify vowel checking
        char current_char = tolower(input_string[i]);

        // Check if the current character is a vowel
        if (current_char == 'a' || current_char == 'e' ||
            current_char == 'i' || current_char == 'o' ||
            current_char == 'u') {
            vowel_count++;
        }
    }

    // Print the total vowel count
    printf("Total vowels: %d\n", vowel_count);

    return 0;
}
